const rows = $input.all();
const source = $items("Edit Fields")[0].json;
const messageText = source.messageText;
const replyToken = source.replyToken;

const [dateText, timeText] = messageText.split(" ");

const availableSeats = rows
  .filter(r => r.json["ว่าง/ไม่ว่าง"] === "ว่าง")
  .map(r => r.json["ที่นั่ง"]);

const seatRows = ["A", "B", "C", "D", "F", "G", "H"];

let result = [];

for (const row of seatRows) {
  const seat1 = availableSeats.includes(row + "1") ? row + "1" : "xx";
  const seat2 = availableSeats.includes(row + "2") ? row + "2" : "xx";
  const seat3 = availableSeats.includes(row + "3") ? row + "3" : "xx";

  // เพิ่มช่องว่างระหว่างคอลัมน์ให้ห่างขึ้น (ใช้ 3-4 spaces)
  // และใส่บรรทัดว่างต่อท้ายแต่ละแถวเพื่อให้ดูโปร่ง
  result.push(`${seat1}   |   ${seat2}   ${seat3}\n`); 
}

const table = result.join(""); // ไม่ต้อง join ด้วย \n เพราะเพิ่มใน push แล้ว

return [
  {
    json: {
      replyToken: replyToken,
      replyText: `📅 รอบวันที่: ${dateText}
⏰ เวลา: ${timeText}
🪑 ที่นั่งว่าง:
${table}
หมายเหตุ: xx = ที่นั่งที่"จองแล้ว"`
    }
  }
];

