const targetDate = $now
  .minus({ days: 1 })
  .plus({ years: 543 })
  .toFormat("d/M/yyyy");

// ดึงไฟล์ทั้งหมดจาก Search
const items = $input.all();

// กรองเฉพาะไฟล์ที่ชื่อ = วันที่เป๊ะ ๆ
