return matched;

const item = $input.item.json;

// วันที่ปัจจุบัน
const now = new Date();

// แปลงเป็นวัน/เดือน/ปี พ.ศ.
const day = now.getDate();
const month = now.getMonth() + 1;
const yearBE = now.getFullYear() + 543;

const todayThai = `${day}/${month}/${yearBE}`;

return [
  {
    json: {
      replyToken: item.replyToken,
      replyText: 
        `🔍 **ตรวจสอบที่นั่งว่าง**\n\n` +
        `กรุณาระบุ **วัน/เดือน/ปี** และ **รอบเวลา**\n` +
        `ที่ท่านต้องการตรวจสอบครับ\n\n` +
        `📝 **รูปแบบการพิมพ์:**\n` +
        `\`วัน/เดือน/ปี เวลา\`\n` +
        `*(ตัวอย่าง: ${todayThai} 06:00)*\n\n` +
        `--- \n\n` +
        `⏰ **รอบเวลาที่เปิดให้บริการ:**\n` +
        `• 🌅 เช้า: 06:00 | 08:00 | 10:00\n` +
        `• ☀️ บ่าย: 12:00 | 14:00 | 16:00\n` +
        `• 🌙 เย็น: 18:00 | 20:00\n\n` +
        `💡 *คำแนะนำ: ท่านสามารถพิมพ์ตามตัวอย่างเพื่อรับข้อมูลได้ทันทีครับ*`
    }
  }
];

return [
  {
    json: {
      message: [
        "สวัสดีครับ 🙏 ยินดีต้อนรับสู่บริการจองรถ",
        "",
        "คุณสามารถพิมพ์คำสั่งที่ต้องการได้เลยครับ:",
        "🔹 พิมพ์ \"วิธีใช้งาน\" เพื่อทำการจองที่นั่ง",
        "🔹 พิมพ์ \"เช็ครอบรถ\" เพื่อตรวจสอบตารางเดินรถ",
        "🔹 พิมพ์ \"ยกเลิก\" เพื่อขอยกเลิกการจอง",
        "",
        "ขอบคุณครับ"
      ].join("\n")
    }
  }
];

// วันที่จาก AI
const aiDate = $items("AI Agent")[0].json.output.date;

// เวลาจาก AI
const aiTime = $items("AI Agent")[0].json.output.time;

// เวลาเที่ยวรถ (จองได้)
const busTimes = ["6:00","8:00","10:00","12:00","14:00","16:00","18:00","20:00"];

// ถ้าเวลาไม่ได้อยู่ในรอบรถ
if (!busTimes.includes(aiTime)) {
  return [{
    status: "error",
    message: "กรุณาเลือกเวลาให้ถูกต้อง"
  }];
}

// ไฟล์ทั้งหมดจาก Google Drive
const driveFiles = $items("Search files and folders");

// หาไฟล์ที่ชื่อ ตรงกับวันที่แบบ exact match
const matched = driveFiles.find(f => f.json.name === aiDate);

if (!matched) {
  return [{
    status: "error",
    message: `ไม่พบไฟล์วันที่ ${aiDate}`
  }];
}

// ส่งต่อเฉพาะไฟล์ที่ match
return [{
  status: "success",
  fileId: matched.json.id,
  fileName: matched.json.name,
  date: aiDate,
  time: aiTime
}];

// ดึงข้อมูลจาก AI Agent
const booking = $items("AI Agent")[0].json.output;

// ดึงข้อมูลจาก Google Sheet
const sheetRows = $items("เลือกเวลา1").map(i => i.json);

// =============================
// 🔥 ตรวจสอบวันเวลา (โซนไทย)
// =============================

if (!booking.date || !booking.time) {
  return [{
    json: {
      status: "error",
      message: "ไม่พบข้อมูลวันเวลาเดินทาง"
    }
  }];
}

// แยกวัน/เดือน/ปี พ.ศ.
const [day, month, yearBE] = booking.date.split("/").map(Number);
const yearAD = yearBE - 543;

// แยกชั่วโมง/นาที
const [hour, minute] = booking.time.split(":").map(Number);

// สร้างเวลา "รอบรถ" แบบ UTC แล้วลบ 7 ชม. เพื่อให้ตรงกับไทย
const bookingUTC = Date.UTC(yearAD, month - 1, day, hour - 7, minute);

// เวลาปัจจุบันจริง (UTC timestamp)
const nowUTC = Date.now();

// ถ้าเวลาปัจจุบันมากกว่าหรือเท่ากับรอบรถ → ห้ามจอง
if (nowUTC >= bookingUTC) {
  return [{
    json: {
      status: "time_expired",
      message: "รอบรถออกไปแล้ว กรุณาเลือกรอบใหม่"
    }
  }];
}

// =============================
// เช็คที่นั่ง
// =============================

const selectedSeats = booking.seats || [];

if (selectedSeats.length === 0) {
  return [{
    json: {
      status: "error",
      message: "ไม่พบข้อมูลที่นั่ง"
    }
  }];
}

// หาเฉพาะแถวที่ลูกค้าเลือก
const selectedRows = sheetRows.filter(row =>
  selectedSeats.includes(row["ที่นั่ง"])
);

// เช็คที่นั่งไม่ว่าง
const unavailable = selectedRows.filter(row =>
  row["ว่าง/ไม่ว่าง"] !== "ว่าง"
);

if (unavailable.length > 0) {
  return [{
    json: {
      status: "unavailable",
      message: "ที่นั่งที่คุณเลือกไม่ว่าง",
      seats: unavailable.map(s => s["ที่นั่ง"])
    }
  }];
}

// =============================
// คำนวณราคา
// =============================

const seatCount = selectedSeats.length;
const pricePerSeat = 70;
const total = seatCount * pricePerSeat;

const seatString = selectedSeats.join(",");

return [{
  json: {
    วันที่เดินทาง: booking.date,
    เวลาเดินทาง: booking.time,
    ชื่อผู้จอง: booking.name,
    เบอร์โทร: booking.phone,
    ที่นั่ง: seatString,
    ราคา: 70,
    ราคารวม: total,
    สถานะการชำระเงิน: "รอชำระ"
  }
}];

const replyToken = $('Edit Fields').item.json.replyToken;

return [
  {
    json: {
      replyToken: replyToken,
      messages: [
        {
          type: "text",
          text: `🚫 ขออภัยครับ รอบรถที่คุณเลือก "ออกเดินทางไปแล้ว"

🕒 กรุณาเลือกดูรอบเวลาใหม่อีกครั้ง
หากต้องการตรวจสอบตารางเดินรถ พิมพ์ "เช็ครอบรถ"`
        }
      ]
    }
  }
];

const replyToken = $('Edit Fields').item.json.replyToken;

return [
  {
    json: {
      replyToken: replyToken,
      messages: [
        {
          type: "text",
          text: `❌ ที่นั่งที่คุณเลือกไม่ว่าง กรุณาเลือกที่นั่งใหม่อีกครั้ง
หากต้องการเช็คที่นั่งพิมพ์ "เช็คที่นั่ง"`
        }
      ]
    }
  }
];

const amount = $input.first().json['ราคารวม'];
const phone = "0902920594";  // เบอร์รับเงิน

return [{
  qrUrl: `https://promptpay.io/${phone}/${amount}`,
  message: `กรุณาชำระเงินจำนวน ${amount} บาท และส่งสลิปกลับมาเพื่อยืนยันการจอง`
}];

// ----- ดึงข้อมูลจาก AI -----
const slip = $items("AI Agent1")[0].json.output;

// ----- ดึงทุกแถวจากชีต -----
const rows = $items("Get row(s) in sheet").map(i => i.json);

// กันกรณีไม่มีข้อมูล
if (!rows.length) {
  return [{
    json: {
      status: "no_data",
      message: "ไม่พบข้อมูลในชีต"
    }
  }];
}

// ----- เลือกแถวที่ลำดับมากที่สุด -----
const sheet = rows
  .sort((a, b) => Number(b["ลำดับ"]) - Number(a["ลำดับ"]))[0];

// ----- เตรียมชื่อ -----
const slipFirstName = (slip.sender || "")
  .trim()
  .split(" ")[0]
  .toLowerCase();

const bookingFirstName = (sheet["ชื่อผู้จอง"] || "")
  .trim()
  .split(" ")[0]
  .toLowerCase();

// ----- เช็คยอด -----
const slipAmount = Number(slip.amount);
const sheetAmount = Number(sheet["ราคารวม"]);

const nameMatch = slipFirstName === bookingFirstName;
const amountMatch = slipAmount === sheetAmount;

// ----- สร้างสถานะ -----
let status = "not_match";
let message = "ชื่อและยอดเงินไม่ตรงกัน";

// clone sheet เพื่อความปลอดภัย
let updatedSheet = { ...sheet };

if (nameMatch && amountMatch) {
  status = "match";
  message = "ชื่อและยอดเงินตรงกัน";
  updatedSheet["สถานะการชำระเงิน"] = "ชำระเงินแล้ว";

} else if (!nameMatch && amountMatch) {
  status = "name_not_match";
  message = "ยอดเงินตรง แต่ชื่อไม่ตรง";

} else if (nameMatch && !amountMatch) {
  status = "amount_not_match";
  message = "ชื่อถูกต้อง แต่ยอดเงินไม่ตรง";
}

// ----- return -----
return [{
  json: {
    status,
    message,
    ...updatedSheet
  }
}];

for (const item of $input.all()) {
  // ใช้ Backticks ( ` ) เพื่อให้พิมพ์เว้นบรรทัดได้ง่ายและอ่านรู้เรื่อง
  item.json.message = `❌ **ทำรายการไม่สำเร็จ**

⚠️ สาเหตุ: ชื่อหรือจำนวนเงินไม่ตรง

กรุณาตรวจสอบข้อมูลแล้ว "ทำรายการใหม่" อีกครั้งนะครับ`;
}

return $input.all();

// ดึงข้อมูลจาก node ก่อนหน้า
const sheet = $items("Update row in sheet1")[0].json;
const driveItems = $items("Search files and folders2");

// --------- 1️⃣ เทียบวันที่ (normalize ก่อน) ---------
function normalizeDate(dateStr) {
  if (!dateStr) return "";

  const parts = dateStr.toString().trim().split("/");
  if (parts.length !== 3) return dateStr.trim();

  const day = parts[0].padStart(2, "0");
  const month = parts[1].padStart(2, "0");
  const year = parts[2];

  return `${day}/${month}/${year}`;
}

const travelDate = normalizeDate(sheet["วันที่เดินทาง"]);

// หา folder ที่ชื่อวันที่ตรงกัน
const matchedFolder = driveItems.find(item => {
  const folderName = normalizeDate(item.json.name);
  return folderName === travelDate;
});

const dateMatch = !!matchedFolder;


// --------- 2️⃣ แยกที่นั่ง (แก้ใหม่) ---------
const seatsRaw = sheet["ที่นั่ง"] || "";

// รองรับ , ช่องว่าง และขึ้นบรรทัดใหม่ + กันที่นั่งซ้ำ
const seatsArray = [...new Set(
  seatsRaw
    .toString()
    .split(/[, \n]+/)
    .map(s => s.trim().toUpperCase())
    .filter(Boolean)
)];


// --------- 3️⃣ แตกเป็นหลาย items เพื่อ update ทีละที่นั่ง ---------
return seatsArray.map(seat => ({
  json: {
    ...sheet,
    "ที่นั่ง": seat,                 // ใช้ match กับ column ใน sheet
    "ว่าง/ไม่ว่าง": "ไม่ว่าง",       // ค่าที่จะ update
    date_match: dateMatch,
    matched_folder_id: matchedFolder ? matchedFolder.json.id : null
  }
}));

const items = $input.all();

// รวมที่นั่ง
const seats = items.map(i => i.json["ที่นั่ง"]).join(",");

// ใช้ข้อมูลจาก item แรก
const first = items[0].json;

return [
  {
    json: {
      ...first,
      "ที่นั่ง": seats,
      "สถานะชำระเงิน": "ชำระเงินเรียบร้อยแล้ว"
    }
  }
];

