return $input.all().map(item => {

  const input = item.json.messageText || "";
  const parts = input.trim().split(/\s+/);

  const dateStr = parts[0];
  let timeStr = parts[1];

  // แปลงเวลา 06:00 -> 6:00
  if (timeStr) {
    const [h, m] = timeStr.split(":");
    timeStr = `${parseInt(h,10)}:${m}`;
  }

  const [day, month, yearBE] = dateStr.split("/").map(Number);
  const [hour, minute] = timeStr.split(":").map(Number);

  const yearAD = yearBE - 543;

  // เวลาเที่ยวรถ
  const selected = new Date(yearAD, month - 1, day, hour, minute, 0);

  // เวลาไทยปัจจุบัน
  const nowThai = new Date(
    new Date().toLocaleString("en-US", { timeZone: "Asia/Bangkok" })
  );

  if (selected.getTime() <= nowThai.getTime()) {
    return {
      json: {
        status: "รถออกไปแล้ว",
        date: dateStr,
        time: timeStr
      }
    };
  }

  return {
    json: {
      status: "ยังไม่ถึงเวลา",
      date: dateStr,
      time: timeStr
    }
  };

});

for (const item of $input.all()) {
  const status = item.json.status;
  const date = item.json.date;
  const time = item.json.time;

  if (status === "รถออกไปแล้ว") {
    item.json.replyMessage = `ขออภัยครับ รถเที่ยวเวลา ${time} ของวันที่ ${date} ได้ออกเดินทางไปแล้ว ไม่สามารถจองหรือแก้ไขได้ในขณะนี้`;
  } else {
    item.json.replyMessage = "สถานะปกติ สามารถดำเนินการต่อได้";
  }
}

return $input.all();

const time = $items("รอบรถ")[0].json.time;

// เวลาที่อนุญาต
const allowedTimes = [
  "6:00",
  "8:00",
  "10:00",
  "12:00",
  "14:00",
  "16:00",
  "18:00",
  "20:00"
];

// เช็คว่าอยู่ในรายการไหม
const isValid = allowedTimes.includes(time);

return [
  {
    json: {
      time: time,
      valid: isValid
    }
