const text = $items("ยืนยันยกเลิก")[0].json.messageText;

// แยกข้อความ
const lines = text.split("\n");

const command = lines[0].trim();
const fullName = lines[1].trim();
const seat = lines[2].trim();

// แยกชื่อ
const nameParts = fullName.split(" ");
const firstName = nameParts[0] || "";
const lastName = nameParts[1] || "";

// ดึงทุกแถวจาก Google Sheet
const rows = $items("Get row(s) in sheet1");

let result = [];

for (const item of rows) {

  const sheetName = (item.json["ชื่อผู้จอง"] || "").trim();
  const sheetSeat = (item.json["ที่นั่ง"] || "").trim();

  // เช็คข้อมูล
  const nameMatch = sheetName === fullName;
  const seatMatch = sheetSeat === seat;
  const match = nameMatch && seatMatch;

  // ถ้าตรงกันให้เอาข้อมูลออกมา
  if (match) {
    result.push({
      json: {
        command,
        firstName,
        lastName,
        fullName,
        seat,

        sheetName,
        sheetSeat,

        nameMatch,
        seatMatch,
        match,

        ...item.json
      }
    });
  }
}

// ถ้าไม่เจอ
if (result.length === 0) {
  return [
    {
      json: {
        found: false,
        message: "ไม่พบข้อมูลที่ตรงกัน"
      }
    }
  ];
}

return result;

